  "verses": [
    {
      "n": 2,
      "column": "left",
      "text": "Rangi un / es eſmu fatwu\nMutti atdarrijs / manna Mehle\nrunna appakſch manna Schohda.\n"
    },
    {
      "n": 3,
      "column": "left",
      "text": "Manna WalloDa iſfazzihs\nmannas SirDs Taifnibu / un\nmannu Luhpu Sinnafchana\n(runnahs) to/ kas fchkihts irr.\n"
    },
    {
      "n": 4,
      "column": "left",
      "text": "Ta STIPRA DEE.\nWA Gars irr manni darrijs/\nun ta Wiſſuwarrena Dwascha\nier manni dſihwu padarrijsi.\n"
    },
    {
      "n": 5,
      "column": "left",
      "text": "Ja tu mahki/ athbildi man/\ntaifajs manna Preekicha / un\nſtahwi ſcheju.\n"
    },
    {
      "n": 6,
      "column": "left",
      "text": "* Rangi/ es peederru tain\nSTIPRAM DEEWAM\nitt ka tu / no Mahleem eſmu es\narri padarrichts.\n* Es eſmu fche ka tawa Mutte irr weblejſt,\nDeewa Weetâ, Luk: Nod: 23. 3.\n"
    },
    {
      "n": 7,
      "column": "left",
      "text": "Redsi/ manna Iſtruhzi-\nnafhana tew ne isbeedehs / un\nmanno Rohka pahr tew ne buhs\ngruhta.\n"
    },
    {
      "n": 8,
      "column": "left",
      "text": "Teefcham/ tu eſſi preekſch\nmannahm Aufim runnajs / to\nWahrdu Balsi eſmu es dsirdejs.\n"
    },
    {
      "n": 9,
      "column": "left",
      "text": "Es eſmu fchkihts bes Pahr-\nkahpfchanas/ es eſmu tihrs / un\nman Roſeeguma newaid.\n"
    },
    {
      "n": 10,
      "column": "left",
      "text": "Rangi / wiſch atrohd\nprett manni Geemeſlus/ tapehz\nturr wiſch mann par tawn Ee-\nnaidneefu.\n"
    },
    {
      "n": 11,
      "column": "left",
      "text": "Wiſch leek mannas Kah-\njas Seckſa / wiſch apfarga\nwiſus mannu Zeltus.\n"
    },
    {
      "n": 12,
      "column": "left",
      "text": "Redsi/ par to paschtu es\n"
    },
    {
      "n": 13,
      "column": "right",
      "text": "Kapehz gribbi tu arw\nnu teefatees? jo wiſch ne at\nno wiſſeem faueem Darbeem\n"
    },
    {
      "n": 14,
      "column": "right",
      "text": "Kad tas STIPRA\nDEEWSweenkahrt fo runn\ntad wiſch to ohtran fahrtai\npahrdohma.\n"
    },
    {
      "n": 15,
      "column": "right",
      "text": "Sapni zaue Para-\nschanahm Nahti / kad &\nMeegs us Zilwekeem friht /\ntee fnansch us tawn Gultu.\n"
    },
    {
      "n": 16,
      "column": "right",
      "text": "Tad atdarra wiſſe\nZilweku Austi / un tetruh\ntohs/ ka wiſch teefcham\ngrib fohdicht.\n"
    },
    {
      "n": 17,
      "column": "right",
      "text": "Ka wiſch to Zilweku\nfawa Darba nowehrſch / un\nwiſch to Wihru no Lepni\npatwer.\n"
    },
    {
      "n": 18,
      "column": "right",
      "text": "Ka tas wiſsa Dwe\nno Samattafchanas noturr/\nwiſna Dſihwihu/ ka tas\nSoſbinu ne friht.\n"
    },
    {
      "n": 19,
      "column": "right",
      "text": "Wiſch arritohp ar G\npehm pahrmatzihts us k\nGultu / un wiſi wiſna K\n(tohp fpaiditi).\n"
    },
    {
      "n": 20,
      "column": "right",
      "text": "Ta ka wiſna Dſihw\nta Maitse reebjahs/ un wi\nDwehfelei wiſfada gahrdn 2\nriba.\n"
    },
    {
      "n": 21,
      "column": "right",
      "text": "Ka wiſna Meeta Wo\nnoginst/ un wiſna Kault tat\nfi tohp/ ka tohs labpraht ne\nluhko.\n"
    },
    {
      "n": 22,
      "column": "right",
      "text": "Un wiſna Dwehfele\ntuwu pee Samaitafchanas/\n"
    }
  ],
  "confidence": "high",
  "notes": ""
}
